={{ (() => {
  const raw = $json.output || '';
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  const parsed = JSON.parse(cleaned);
  const idea = parsed.selectedIdea;
  return JSON.stringify({
    assignments: [
      { name: 'videoTitle', value: idea.title, type: 'string' },
      { name: 'hook', value: idea.hook, type: 'string' },
      { name: 'fullScript', value: idea.narration, type: 'string' },
      { name: 'scenes', value: idea.scenes, type: 'array' },
      { name: 'caption', value: idea.caption, type: 'string' },
      { name: 'viralScore', value: idea.viralScore, type: 'number' },
      { name: 'angle', value: idea.angle, type: 'string' },
      { name: 'fieldOfStudy', value: idea.fieldOfStudy, type: 'string' },
      { name: 'wordCount', value: idea.narration.split(/\s+/).length, type: 'number' }
    ]
  });
})() }}
